parameters.pythonCode:
Youtube_Title = _input.first().json.snippet.title

prompt = f"""
You are connected to a spreadsheet tool. Retrieve all the data related to this YouTube video:
Title: {Youtube_Title}

Output format MUST be exact JSON like this:

{{
  "Data": [
    {{
      "row_number": 1,
      "Date": "MM/DD/YYYY",
      "Time": "HH:MM",
      "YouTube Title": "...",
      "YouTube Description": "...",
      "TikTok Description": "...",
      "Facebook Reel Description": "...",
      "Instagram Description": "...",
      "Additional Notes": {{
        "Hashtags": [...],
        "Trends": [...],
        "PostingTips": [...]
      }},
      "Video Url View": "...",
      "Video Url Download": "...",
      "col_11": "..."
    }}
  ]
}}

No extra words, no explanations, no quotes around the outer JSON. Return only valid JSON.
"""

return {"chatInput": prompt}

parameters.jsCode:
let aiOutput = $json["output"];

aiOutput = aiOutput.replace(/^```json\s*|\s*```$/g, '');

const parsedOutput = JSON.parse(aiOutput);

const dataArray = parsedOutput.Data;

const finalArray = typeof dataArray === 'string' ? JSON.parse(dataArray) : dataArray;

return finalArray.map(item => ({ json: item }));
